async (params, browser) => {
  // Search IMDb
  await browser.open(`https://www.imdb.com/find/?q=${params.query}`)

  // Wait for search results
  await browser.waitForSelector('[data-testid=\'find-results-section-title\'], .ipc-metadata-list-summary-item, [class*=\'find-result\']', 15000)

  // Let results render
  await browser.wait(2000)

  // Scroll to load more
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1500)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.ipc-metadata-list-summary-item, [class*="ipc-metadata-list-summary-item"]'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('.ipc-title__text, a[href*="/title/"], a[href*="/name/"]'); const metaItems = el.querySelectorAll('.ipc-inline-list__item, [class*="cli-title-metadata-item"]'); let year = ''; let type = ''; for (const m of metaItems) { const t = m.textContent.trim(); if (/^\d{4}/.test(t)) { year = t; } else if (t && !year) { type = t; } } const linkEl = el.querySelector('a[href*="/title/"], a[href*="/name/"]'); const imgEl = el.querySelector('img'); results.push({ title: titleEl ? titleEl.textContent.trim().replace(/^\d+\.\s*/, '') : '', year: year, type: type, url: linkEl ? linkEl.href : '', image: imgEl ? imgEl.getAttribute('src') : '' }); } return { query: '' + params.query + '', result_count: results.length, results: results }`)

  return search_results
}
